export default function MetricCard({ label, value, helper, tone = 'primary' }) {
  return (
    <div className="card admin-mentor-card h-100">
      <div className="card-body">
        <div className={`admin-mentor-metric-icon text-bg-${tone}`}>{String(label).slice(0, 1)}</div>
        <p className="text-secondary small mb-1">{label}</p>
        <h2 className="h4 mb-1">{value}</h2>
        {helper ? <p className="small text-secondary mb-0">{helper}</p> : null}
      </div>
    </div>
  );
}
